import React, { useState, useEffect } from 'react';

const HOLES = 9;
const DURATION = 20;

export default function WhackAMole() {
  const [active, setActive] = useState(-1);
  const [score, setScore] = useState(0);
  const [time, setTime] = useState(DURATION);
  const [playing, setPlaying] = useState(false);

  useEffect(() => {
    if (!playing) return;
    const id = setInterval(() => setActive(Math.floor(Math.random() * HOLES)), 700);
    return () => clearInterval(id);
  }, [playing]);

  useEffect(() => {
    if (!playing) return;
    const id = setInterval(() => {
      setTime((t) => {
        if (t <= 1) {
          setPlaying(false);
          setActive(-1);
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [playing]);

  const start = () => {
    setScore(0);
    setTime(DURATION);
    setActive(-1);
    setPlaying(true);
  };

  const whack = (i) => {
    if (playing && i === active) {
      setScore((s) => s + 1);
      setActive(-1);
    }
  };

  return (
    <div style={{ maxWidth: 300 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 600, marginBottom: 12 }}>
        <span>Score: {score}</span>
        <span>Time: {time}s</span>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 10 }}>
        {Array.from({ length: HOLES }, (_, i) => (
          <button
            key={i}
            onClick={() => whack(i)}
            style={{ height: 80, fontSize: 36, cursor: 'pointer', borderRadius: '50%', border: 'none', background: i === active ? '#92400e' : '#d1d5db' }}
          >
            {i === active ? '🐹' : ''}
          </button>
        ))}
      </div>
      <button onClick={start} disabled={playing} style={{ marginTop: 14, padding: '8px 16px', cursor: playing ? 'default' : 'pointer' }}>
        {playing ? 'Playing…' : time === 0 ? `Play again (last: ${score})` : 'Start'}
      </button>
    </div>
  );
}

