import { Component, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-whack-a-mole',
  template: `
    <div style="max-width: 300px;">
      <div style="display: flex; justify-content: space-between; font-weight: 600; margin-bottom: 12px;">
        <span>Score: {{ score }}</span>
        <span>Time: {{ time }}s</span>
      </div>
      <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px;">
        <button
          *ngFor="let h of holesArr; let i = index"
          (click)="whack(i)"
          [style.background]="i === active ? '#92400e' : '#d1d5db'"
          style="height: 80px; font-size: 36px; cursor: pointer; border-radius: 50%; border: none;"
        >{{ i === active ? '🐹' : '' }}</button>
      </div>
      <button (click)="start()" [disabled]="playing" style="margin-top: 14px; padding: 8px 16px; cursor: pointer;">
        {{ playing ? 'Playing…' : (time === 0 ? 'Play again (last: ' + score + ')' : 'Start') }}
      </button>
    </div>
  `,
})
export class WhackAMoleComponent implements OnDestroy {
  readonly HOLES = 9;
  readonly DURATION = 20;
  holesArr = Array(9).fill(0);
  active = -1;
  score = 0;
  time = 20;
  playing = false;
  private spawnId: any = null;
  private tickId: any = null;

  stop(): void {
    this.playing = false;
    this.active = -1;
    clearInterval(this.spawnId);
    clearInterval(this.tickId);
  }

  tick(): void {
    this.time--;
    if (this.time <= 0) {
      this.time = 0;
      this.stop();
    }
  }

  start(): void {
    this.score = 0;
    this.time = this.DURATION;
    this.active = -1;
    this.playing = true;
    clearInterval(this.spawnId);
    clearInterval(this.tickId);
    this.spawnId = setInterval(() => {
      this.active = Math.floor(Math.random() * this.HOLES);
    }, 700);
    this.tickId = setInterval(() => this.tick(), 1000);
  }

  whack(i: number): void {
    if (this.playing && i === this.active) {
      this.score++;
      this.active = -1;
    }
  }

  ngOnDestroy(): void {
    this.stop();
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Whack-a-Mole Demo</h1>
      <app-whack-a-mole></app-whack-a-mole>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, WhackAMoleComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
